DDL:
DROP TABLE IF EXISTS DIM_GEOGRAPHY_HIERARCHY CASCADE;
CREATE TABLE DIM_GEOGRAPHY_HIERARCHY (
	HIERARCHY_ID BIGINT PRIMARY KEY,
	LOCATION_NAME VARCHAR(100),
	LOCATION_TYPE VARCHAR(20),
	COUNTRY VARCHAR(20),
	STATE VARCHAR(100),
	DISTRICT VARCHAR(50),
	SUB_DISTRICT VARCHAR(100)
);

DROP TABLE IF EXISTS FACT_HOUSING CASCADE;
CREATE TABLE FACT_HOUSING (
	HOUSING_ID BIGINT PRIMARY KEY,
	HIERARCHY_ID BIGINT,
	CENSUS_YEAR INTEGER,
	NUMBER_OF_OCCUPIED_RESIDENTIAL_HOUSES DOUBLE PRECISION,
	NUMBER_OF_HOUSEHOLDS DOUBLE PRECISION
);

DROP TABLE IF EXISTS FACT_POPULATION_AGE_COHORT CASCADE;
CREATE TABLE FACT_POPULATION_AGE_COHORT (
	POPULATION_AGE_ID BIGINT PRIMARY KEY,
	HIERARCHY_ID BIGINT,
	CENSUS_YEAR INTEGER,
	MALE_POPULATION_0_TO_6_YEARS DOUBLE PRECISION,
	FEMALE_POPULATION_0_TO_6_YEARS DOUBLE PRECISION
);

DROP TABLE IF EXISTS FACT_POPULATION_CORE CASCADE;
CREATE TABLE FACT_POPULATION_CORE (
	POPULATION_CORE_ID BIGINT PRIMARY KEY,
	HIERARCHY_ID BIGINT,
	CENSUS_YEAR INTEGER,
	TOTAL_POPULATION DOUBLE PRECISION,
	TOTAL_MALE_POPULATION DOUBLE PRECISION,
	TOTAL_FEMALE_POPULATION DOUBLE PRECISION
);

DROP TABLE IF EXISTS FACT_POPULATION_LITERACY CASCADE;
CREATE TABLE FACT_POPULATION_LITERACY (
	POPULATION_LITERACY_ID BIGINT PRIMARY KEY,
	HIERARCHY_ID BIGINT,
	CENSUS_YEAR INTEGER,
	MALE_ILLITERATE_POPULATION DOUBLE PRECISION,
	FEMALE_ILLITERATE_POPULATION DOUBLE PRECISION
);

DROP TABLE IF EXISTS FACT_POPULATION_SOCIAL_CATEGORY CASCADE;
CREATE TABLE FACT_POPULATION_SOCIAL_CATEGORY (
	POPULATION_SOCIAL_ID BIGINT PRIMARY KEY,
	HIERARCHY_ID BIGINT,
	CENSUS_YEAR INTEGER,
	MALE_SCHEDULED_CASTE_POPULATION DOUBLE PRECISION,
	FEMALE_SCHEDULED_CASTE_POPULATION DOUBLE PRECISION,
	MALE_SCHEDULED_TRIBE_POPULATION DOUBLE PRECISION,
	FEMALE_SCHEDULED_TRIBE_POPULATION DOUBLE PRECISION
);

DROP TABLE IF EXISTS FACT_WORKFORCE_DETAIL CASCADE;
CREATE TABLE FACT_WORKFORCE_DETAIL (
	WORKFORCE_DETAIL_ID BIGINT PRIMARY KEY,
	HIERARCHY_ID BIGINT,
	CENSUS_YEAR INTEGER,
	MALE_MARGINAL_WORKERS DOUBLE PRECISION,
	FEMALE_MARGINAL_WORKERS DOUBLE PRECISION,
	MALE_NON_WORKERS DOUBLE PRECISION,
	FEMALE_NON_WORKERS DOUBLE PRECISION
);

DROP TABLE IF EXISTS FACT_WORKFORCE_STATUS CASCADE;
CREATE TABLE FACT_WORKFORCE_STATUS (
	WORKFORCE_STATUS_ID BIGINT PRIMARY KEY,
	HIERARCHY_ID BIGINT,
	CENSUS_YEAR INTEGER,
	MALE_WORKING_POPULATION DOUBLE PRECISION,
	FEMALE_WORKING_POPULATION DOUBLE PRECISION
);
